  // ─────────────────────────────────────────────
  //  VALIDATIONS
  // ─────────────────────────────────────────────
  validateStep1() {
    this.errors = {};
    let ok = true;
    const d = this.step1;
    if (!d.accountType) {
      this.errors.accountType = "Required";
      ok = false;
    }
    if (!d.fullName?.trim()) {
      this.errors.fullName = "Required";
      ok = false;
    }
    if (!d.fatherName?.trim()) {
      this.errors.fatherName = "Required";
      ok = false;
    }
    if (!d.motherName?.trim()) {
      this.errors.motherName = "Required";
      ok = false;
    }
    if (!d.dateOfBirth) {
      this.errors.dateOfBirth = "Required";
      ok = false;
    }
    if (!d.gender) {
      this.errors.gender = "Required";
      ok = false;
    }
    if (!d.occupation?.trim()) {
      this.errors.occupation = "Required";
      ok = false;
    }
    if (!d.phoneNumber) {
      this.errors.phoneNumber = "Required";
      ok = false;
    } else if (!/^[6-9]\d{9}$/.test(d.phoneNumber)) {
      this.errors.phoneNumber = "Enter valid 10-digit mobile number";
      ok = false;
    }
    if (!d.emailId) {
      this.errors.emailId = "Required";
      ok = false;
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(d.emailId)) {
      this.errors.emailId = "Enter valid email";
      ok = false;
    }
    if (!d.aadhaarNumber) {
      this.errors.aadhaarNumber = "Required";
      ok = false;
    } else if (!/^\d{12}$/.test(d.aadhaarNumber)) {
      this.errors.aadhaarNumber = "Enter valid 12-digit Aadhaar";
      ok = false;
    }
    if (!d.panNumber) {
      this.errors.panNumber = "Required";
      ok = false;
    } else if (!/^[A-Z]{5}[0-9]{4}[A-Z]{1}$/.test(d.panNumber.toUpperCase())) {
      this.errors.panNumber = "Enter valid PAN (e.g. ABCDE1234F)";
      ok = false;
    }
    return ok;
  }
  validateStep2() {
    this.errors = {};
    let ok = true;
    const a = this.step2;
    if (!a.currentAddressLine?.trim()) {
      this.errors.currentAddressLine = "Required";
      ok = false;
    }
    if (!a.currentCity?.trim()) {
      this.errors.currentCity = "Required";
      ok = false;
    }
    if (!a.currentState?.trim()) {
      this.errors.currentState = "Required";
      ok = false;
    }
    if (!a.currentPincode || !/^\d{6}$/.test(a.currentPincode)) {
      this.errors.currentPincode = "6-digit pincode required";
      ok = false;
    }
    if (!a.permanentAddressLine?.trim()) {
      this.errors.permanentAddressLine = "Required";
      ok = false;
    }
    if (!a.permanentCity?.trim()) {
      this.errors.permanentCity = "Required";
      ok = false;
    }
    if (!a.permanentState?.trim()) {
      this.errors.permanentState = "Required";
      ok = false;
    }
    if (!a.permanentPincode || !/^\d{6}$/.test(a.permanentPincode)) {
      this.errors.permanentPincode = "6-digit pincode required";
      ok = false;
    }
    return ok;
  }
  validateStep3() {
    this.errors = {};
    let ok = true;
    const n = this.step3;
    if (!n.nomineeName?.trim()) {
      this.errors.nomineeName = "Required";
      ok = false;
    }
    if (!n.nomineeRelation) {
      this.errors.nomineeRelation = "Required";
      ok = false;
    }
    if (!n.nomineeAge || Number(n.nomineeAge) < 1 || Number(n.nomineeAge) > 120) {
      this.errors.nomineeAge = "Enter valid age";
      ok = false;
    }
    if (!n.nomineeMobileNumber || !/^\d{10}$/.test(n.nomineeMobileNumber)) {
      this.errors.nomineeMobileNumber = "Enter valid 10-digit number";
      ok = false;
    }
    if (!n.nomineeAddress?.trim()) {
      this.errors.nomineeAddress = "Required";
      ok = false;
    }
    return ok;
  }
  validateStep4() {
    this.errors = {};
    let ok = true;
    const required = [
      ["aadhaarCardFile", "Aadhaar Card is required"],
      ["panCardFile", "PAN Card is required"],
      ["profilePhoto", "Profile photo is required"],
      ["signatureImage", "Signature image is required"],
      ["addressProofDocument", "Address proof is required"]
    ];
    required.forEach(([field, msg]) => {
      if (!this.docs[field]) {
        this.errors[field] = msg;
        ok = false;
      }
    });
    return ok;
  }
  validateStep5() {
    this.errors = {};
    let ok = true;
    if (!this.captchaUserInput || this.captchaUserInput.toUpperCase() !== this.captchaCode()) {
      this.errors.captcha = "Captcha does not match.";
      this.refreshCaptcha();
      ok = false;
    }
    if (!this.confirmCheck) {
      this.errors.confirmCheck = "Please confirm all details are correct.";
      ok = false;
    }
    return ok;
  }
  // ─────────────────────────────────────────────
  //  SUBMIT — uses JWT auth (no OTP)
  // ─────────────────────────────────────────────
  submitApplication() {
    if (!this.validateStep5())
      return;
    this.loading.set(true);
    this.error.set("");
    const formData = new FormData();
    Object.entries(this.step1).forEach(([k, v]) => formData.append(k, v ?? ""));
    Object.entries(this.step2).forEach(([k, v]) => formData.append(k, String(v)));
    Object.entries(this.step3).forEach(([k, v]) => formData.append(k, v ?? ""));
    Object.entries(this.docs).forEach(([k, f]) => {
      if (f)
        formData.append(k, f, f.name);
    });
    this.applicationService.submitApplicationAuthenticated(formData).subscribe({
      next: (res) => {
        this.loading.set(false);
        if (res.success && res.data) {
          this.applicationId.set(res.data.applicationId);
          this.submittedData.set(res.data);
          this.showSuccess.set(true);
          this.success.set("Application submitted successfully!");
          this.notificationService.show("Application submitted successfully!", "success");
          window.scrollTo(0, 0);
          setTimeout(() => {
            if (!this.pdfDownloaded) {
              this.pdfDownloaded = true;
              this.downloadPDF();
            }
          }, 3e3);
          this.applicationSubmitted.emit();
        } else {
          const msg = res.message || "Submission failed. Please try again.";
          this.error.set(msg);
          this.notificationService.show(msg, "danger");
        }
      },
      error: (err) => {
        this.loading.set(false);
        const code = err.error?.errorCode || "";
        const message = err.error?.message || "";
        if (code === "ACTIVE_APPLICATION_EXISTS") {
          this.error.set(message);
          this.notificationService.show(message, "warning");
          this.step.set(1);
          window.scrollTo(0, 0);
        } else {
          const msg = message || "Submission failed. Please try again.";
          this.error.set(msg);
          this.notificationService.show(msg, "danger");
        }
      }
    });
  }
